//! sqlx (axum + raw `sqlx::query_as`) emitter for the
//! [`HandlerKind::CsrfFormPostEngineCall`] kind.
//!
//! The seaorm sibling at `crate::codegen::emit_csrf_form_post`
//! (`codegen/mod.rs:909`) emits an `axum::Form` + `dto::emit_form_dto` handler
//! that flashes and redirects. This emitter is API-first: the same form is
//! read as `Json<Dto>`, and the write is a raw SQL `INSERT … RETURNING *`
//! bound directly through `query_as`. The shape divides cleanly in two:
//!
//! 1. **With a resolvable primary model**: emit the form DTO struct, then an
//!    `INSERT INTO <table> (<scope cols>, <form fields>) VALUES ($1, …)
//!    RETURNING *` and wrap the freshly-created row in a `201 Created` HAL
//!    envelope.
//! 2. **Without a resolvable model** (e.g. a bulk service call that invokes a
//!    method rather than writing a single row): emit the form DTO struct plus
//!    a documented `CALIBRATION` body returning `202 Accepted` — the engine
//!    call is left to the porter (Iron Rule 1: never emit `todo!()` into a
//!    compilable production path).
//!
//! The shape is byte-faithful to the openproject-axum-sqlx target goldens at
//! `tests/golden/codegen/sqlx/expected/csrf_form_post_{with_model,stub}.rs`
//! so the integration test trims output and compares it to the expected
//! files.
//!
//! Inert until the orchestrator wires `pub mod csrf_form_post;` into the
//! parent `sqlx_emit` module — the file is self-contained and pulls no
//! private helpers from `codegen::mod`.
//!
//! ## Column policy
//!
//! The `INSERT` column list is the path-param scope columns (the path-param
//! names verbatim — Flask path params are already snake_case lower, e.g.
//! `project_id`) **first**, then the form fields in source order. Scope
//! columns bind by value (`.bind(project_id)`); form fields bind by reference
//! (`.bind(&form.<field>)`) since the DTO owns them. Placeholders are
//! `$1, $2, …` with a count matching the combined column list.

use std::fmt::Write as _;

use crate::codegen::Emitted;
use crate::codegen::target::TargetSpec;
use crate::contract::{PathParam, RouteContract};

/// Emit a sqlx (axum + `sqlx::query_as`) csrf-form-post handler for one route
/// contract against `spec`. The output is a complete, compileable Rust file
/// under the caller's choice of `handler_file` name; when no primary model can
/// be resolved against the spec, the write is replaced with a documented
/// `CALIBRATION` body that returns `202 Accepted` (Iron Rule 1: never emit
/// `todo!()`/`unimplemented!()` into a compilable production path).
pub fn emit_csrf_form_post_sqlx(contract: &RouteContract, spec: &TargetSpec) -> Emitted {
    let fn_name = &contract.function;
    let axum = axum_path(&contract.path);
    let scoping = if contract.guards.is_empty() {
        "none".to_string()
    } else {
        contract.guards.join(", ")
    };

    let header = format!(
        "//! endpoint:     {endpoint}\n\
         //! flask path:   {flask}\n\
         //! axum path:    {axum}\n\
         //! method:       {method}\n\
         //! source:       {file}:{line}\n\
         //! handler_kind: csrf_form_post_engine_call\n\
         //! scoping:      {scoping}\n\
         //\n\
         // GENERATED by ruff_python_codegen — DO NOT EDIT.\n\
         // Modify target-spec/openproject-axum-sqlx.toml instead.\n",
        endpoint = contract.id,
        flask = contract.path,
        method = contract.methods.join(","),
        file = contract.provenance.file,
        line = contract.provenance.line_start,
    );

    // The form DTO struct is shared by both branches: one `Option<String>`
    // field per observed form key, named verbatim.
    let form_struct = format!("{}Form", to_pascal(fn_name));
    let form_dto = form_dto(&form_struct, &contract.inputs.form_fields);

    let (referenced_models, body) = match primary_model(contract, spec) {
        Some((py_class, module_path)) => {
            // Build the model struct path inline. The sqlx target does NOT
            // append `::Model` (that suffix is seaorm-specific); the struct
            // *is* the row type implementing `FromRow`.
            let model_struct = format!("{}::{}::{py_class}", spec.models_root, module_path);
            let table = pluralize_snake(py_class);

            let params: &[PathParam] = &contract.inputs.path_params;
            let extract_import = extract_import(params);
            let path_extractor = path_extractor_line(params);
            let columns = insert_columns(params, &contract.inputs.form_fields);
            let placeholders = placeholders(params.len() + contract.inputs.form_fields.len());
            let bindings = bind_lines(params, &contract.inputs.form_fields);

            let body = format!(
                "\n\
                 use axum::extract::{extract_import};\n\
                 use axum::http::StatusCode;\n\
                 use axum::response::IntoResponse;\n\
                 use axum::Json;\n\
                 \n\
                 use crate::error::{{ApiError, ApiResult}};\n\
                 use crate::extractors::{{AppState, AuthenticatedUser, HalResponse}};\n\
                 use {model_struct};\n\
                 \n\
                 {form_dto}\
                 \n\
                 pub async fn {fn_name}(\n\
                 \x20   State(state): State<AppState>,\n\
                 \x20   _user: AuthenticatedUser,\n\
                 {path_extractor}\
                 \x20   Json(form): Json<{form_struct}>,\n\
                 ) -> ApiResult<impl IntoResponse> {{\n\
                 \x20   let pool = state.pool()?;\n\
                 \x20   let created: {py_class} = sqlx::query_as::<_, {py_class}>(\n\
                 \x20       r#\"INSERT INTO {table} ({columns}) VALUES ({placeholders}) RETURNING *\"#,\n\
                 \x20   )\n\
                 {bindings}\
                 \x20   .fetch_one(&pool)\n\
                 \x20   .await\n\
                 \x20   .map_err(|e| ApiError::internal(format!(\"Database error: {{}}\", e)))?;\n\
                 \n\
                 \x20   Ok((StatusCode::CREATED, HalResponse(created)))\n\
                 }}\n",
            );
            (vec![py_class.to_string()], body)
        }
        None => {
            let body = format!(
                "\n\
                 use axum::extract::State;\n\
                 use axum::http::StatusCode;\n\
                 use axum::response::IntoResponse;\n\
                 use axum::Json;\n\
                 \n\
                 use crate::error::ApiResult;\n\
                 use crate::extractors::{{AppState, AuthenticatedUser}};\n\
                 \n\
                 {form_dto}\
                 \n\
                 pub async fn {fn_name}(\n\
                 \x20   State(state): State<AppState>,\n\
                 \x20   _user: AuthenticatedUser,\n\
                 \x20   Json(form): Json<{form_struct}>,\n\
                 ) -> ApiResult<impl IntoResponse> {{\n\
                 \x20   let _pool = state.pool()?;\n\
                 \x20   let _ = &form;\n\
                 \x20   // CALIBRATION: no model mapping for this form post; implement the engine\n\
                 \x20   // call against the Python source (the body invokes a service method, not a\n\
                 \x20   // direct model write). EXTRACTOR-GAP: add a [models.<Class>] entry to the\n\
                 \x20   // target spec, or extend the extractor if the model reference was missed.\n\
                 \x20   Ok(StatusCode::ACCEPTED)\n\
                 }}\n",
            );
            (contract.data.models.clone(), body)
        }
    };

    Emitted {
        handler_rs: format!("{header}{body}"),
        view_html: None,
        handler_file: format!("{}__{}.rs", contract.family, fn_name),
        view_file: None,
        referenced_models,
        provided_context_keys: Vec::new(),
    }
}

/// Flask `<int:foo>` / `<foo>` → axum `:foo`. Mirrors the helper in
/// `codegen::mod` (private there); inlined to keep this module
/// self-contained — see the file-level doc-comment.
fn axum_path(flask_path: &str) -> String {
    let mut out = String::with_capacity(flask_path.len());
    let mut rest = flask_path;
    while let Some(open) = rest.find('<') {
        out.push_str(&rest[..open]);
        let after = &rest[open + 1..];
        let Some(close) = after.find('>') else {
            out.push_str(&rest[open..]);
            return out;
        };
        let inner = &after[..close];
        let name = inner.split_once(':').map_or(inner, |(_, n)| n);
        out.push(':');
        out.push_str(name);
        rest = &after[close + 1..];
    }
    out.push_str(rest);
    out
}

/// Resolve the first mapped model in `contract.data.models`. Returns
/// `(python_class, module_path)` — the python class is kept verbatim so the
/// generated sqlx struct reference is `crate::models::<module>::<Class>`
/// (the sqlx target does NOT append `::Model`; that suffix is seaorm-only).
fn primary_model<'a>(
    contract: &'a RouteContract,
    spec: &'a TargetSpec,
) -> Option<(&'a str, &'a str)> {
    for m in &contract.data.models {
        if let Some((k, v)) = spec.models.get_key_value(m) {
            return Some((k.as_str(), v.module_path.as_str()));
        }
    }
    None
}

/// Render the form DTO: a `#[derive(Debug, serde::Deserialize)]` struct named
/// `<Function>Form` with one `pub <field>: Option<String>,` line per observed
/// form key. The mirror of the seaorm `dto::emit_form_dto`, inlined here so
/// the module stays self-contained. The returned string ends with a trailing
/// newline so the call site can splice it before the blank-line separator.
fn form_dto(struct_name: &str, fields: &[String]) -> String {
    let mut out = String::new();
    let _ = writeln!(out, "#[derive(Debug, serde::Deserialize)]");
    let _ = writeln!(out, "pub struct {struct_name} {{");
    for field in fields {
        let _ = writeln!(out, "    pub {field}: Option<String>,");
    }
    let _ = writeln!(out, "}}");
    out
}

/// The `axum::extract::{…}` import contents for the with-model branch. When
/// the route carries path params we bring in `Path` alongside `State`; with
/// no path params there is no `Path` extractor so we import `State` alone
/// (keeps the emitted file warning-clean).
fn extract_import(params: &[PathParam]) -> &'static str {
    if params.is_empty() {
        "State"
    } else {
        "{Path, State}"
    }
}

/// Map a Flask path converter to the sqlx-bind Rust type. The sqlx target
/// uses `i64` (Postgres `BIGINT`) for integers — matches the
/// [`detail_for_tenant`] sibling so emitted handlers compose across kinds.
fn flask_conv_to_sqlx_rust(converter: Option<&str>) -> &'static str {
    match converter {
        Some("int") => "i64",
        Some("float") => "f64",
        _ => "String",
    }
}

/// Build the `Path(...)` extractor line for the with-model branch, including
/// its own leading indent and trailing newline so the call site can splice it
/// directly. For zero path params the line is omitted entirely (empty string)
/// — there is nothing to scope the insert by, and the `extract_import` helper
/// drops `Path` from the imports in lockstep. One param emits
/// `Path(project_id): Path<i64>`; several emit axum's tuple-destructure form.
fn path_extractor_line(params: &[PathParam]) -> String {
    match params {
        [] => String::new(),
        [p] => format!(
            "    Path({}): Path<{}>,\n",
            p.name,
            flask_conv_to_sqlx_rust(p.converter.as_deref())
        ),
        many => {
            let names = many
                .iter()
                .map(|p| p.name.as_str())
                .collect::<Vec<_>>()
                .join(", ");
            let tys = many
                .iter()
                .map(|p| flask_conv_to_sqlx_rust(p.converter.as_deref()))
                .collect::<Vec<_>>()
                .join(", ");
            format!("    Path(({names})): Path<({tys})>,\n")
        }
    }
}

/// Build the `INSERT` column list: scope columns (path-param names verbatim,
/// in URL order) first, then the form fields in source order, comma-joined.
/// Flask path params are already snake_case lower so they double as SQL
/// column names without transformation.
fn insert_columns(params: &[PathParam], fields: &[String]) -> String {
    let mut cols: Vec<&str> = Vec::with_capacity(params.len() + fields.len());
    cols.extend(params.iter().map(|p| p.name.as_str()));
    cols.extend(fields.iter().map(String::as_str));
    cols.join(", ")
}

/// Build the `$1, $2, …` placeholder list for `n` columns.
fn placeholders(n: usize) -> String {
    let mut out = String::new();
    for i in 1..=n {
        if i > 1 {
            out.push_str(", ");
        }
        let _ = write!(out, "${i}");
    }
    out
}

/// Build the `.bind(...)` lines in `$1, $2, …` order: scope params first (bound
/// by value — they are `Copy`/owned locals from the `Path` extractor), then
/// the form fields (bound by reference — the DTO owns them). Each line carries
/// its own leading indent and trailing newline so the call site can splice
/// without further formatting.
fn bind_lines(params: &[PathParam], fields: &[String]) -> String {
    let mut out = String::new();
    for p in params {
        let _ = writeln!(out, "    .bind({})", p.name);
    }
    for field in fields {
        let _ = writeln!(out, "    .bind(&form.{field})");
    }
    out
}

/// `WorkPackage` → `work_packages`, `User` → `users`. Naïve snake_case + `s`
/// suffix; mirrors the [`detail_for_tenant`] sibling. Already-plural roots
/// ending in `s` survive untouched.
fn pluralize_snake(class: &str) -> String {
    let snake = to_snake_case(class);
    if snake.ends_with('s') {
        snake
    } else {
        format!("{snake}s")
    }
}

fn to_snake_case(class: &str) -> String {
    let mut out = String::with_capacity(class.len() + 4);
    for (i, ch) in class.chars().enumerate() {
        if ch.is_ascii_uppercase() {
            if i > 0 {
                out.push('_');
            }
            out.push(ch.to_ascii_lowercase());
        } else {
            out.push(ch);
        }
    }
    out
}

/// `create_work_package` → `CreateWorkPackage`. Underscores are treated as
/// word boundaries; each segment is title-cased and concatenated. Used to
/// build the form DTO struct name (`<Function>Form`).
fn to_pascal(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for part in s.split('_') {
        let mut chars = part.chars();
        if let Some(first) = chars.next() {
            out.extend(first.to_uppercase());
            out.push_str(chars.as_str());
        }
    }
    out
}
